/**
 * M1 code representing a member's highest completed education level.
 * - `"SHIGHS"` — Some High School
 * - `"HIGHD"` — High School Diploma / GED
 * - `"SCOLL"` — Some College
 * - `"ASC"` — Associate's Degree
 * - `"BA"` — Bachelor's Degree
 * - `"SGRAD"` — Some Graduate School
 * - `"GRADD"` — Graduate Degree (Master's)
 * - `"PHD"` — Doctorate (PhD / JD / MD)
 */
export type EducationLevelCode = "SHIGHS" | "HIGHD" | "SCOLL" | "ASC" | "BA" | "SGRAD" | "GRADD" | "PHD";